UPDATE `blog_tag` t SET `use_count` = (SELECT COUNT(*) FROM `blog_article_tag` atg WHERE atg.`tag_name` = t.`name` AND atg.`deleted_at` IS NULL) WHERE t.`name` IN ('ElasticSearch', 'Java 8', 'MongoDB', 'MySQL', 'NoSQL - ElasticSearch', 'NoSQL - MongoDB', 'NoSQL - Redis', 'Redis', 'SQL - MySQL', 'SQL 语言', 'Spring', '数据库', '数据库基础和原理', '架构设计', '源码解析', '算法');

UPDATE `blog_column` c SET `article_count` = (SELECT COUNT(*) FROM `blog_column_article` ca INNER JOIN `blog_article` a ON a.`id` = ca.`article_id` WHERE ca.`column_id` = c.`id` AND ca.`deleted_at` IS NULL AND a.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED') WHERE c.`id` IN (9200003);

UPDATE `blog_topic` t SET `article_count` = (SELECT COUNT(*) FROM `blog_topic_article` ta INNER JOIN `blog_article` a ON a.`id` = ta.`article_id` WHERE ta.`topic_id` = t.`id` AND ta.`deleted_at` IS NULL AND a.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED') WHERE t.`id` IN (9303001, 9303002, 9303003, 9303004, 9303005, 9303006);

