INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES
(300000,1,'♥数据库基础和SQL知识体系详解♥','暂无摘要','# ♥数据库基础和SQL知识体系详解♥\n\n> 本系列主要介绍数据库相关的知识体系。@pdai\n\n## 知识体系结构\n\n![图片](/api/uploads/files/pdai/db-539aa03bdb.png)\n\n### 数据库基础与理论\n\n*相关文章*\n\n> **A. 了解数据库基础和理论知识**：在学习数据库之前，不要一上来就是SQL语句；这里建议从数据结构开始切入到数据库，然后再理解数据库是如何工作的，紧接着理解数据库系统的原理知识点和相关知识体系。\n\n- [SQL DB - 资料汇总](https://pdai.tech/md/db/sql/sql-db.html)\n- [SQL DB - 关系型数据库是如何工作的](https://pdai.tech/md/db/sql/sql-db-howitworks.html)很多人在学习数据库时都是孤立的学习知识点，这样是很难将所有知识点串起来深入理解；强烈推荐你学习两篇文章：[Architecture of a Database System在新窗口打开](https://dsf.berkeley.edu/papers/fntdb07-architecture.pdf)以及[How does a relational database work在新窗口打开](http://coding-geek.com/how-databases-work)；本文主要在第二篇基础上翻译并梳理，如果你英文不好的话，你可以通过本文帮助你构筑数据库体系的基础\n- [SQL DB - 关系型数据库设计理论](https://pdai.tech/md/db/sql/sql-db-theory-concept.html)在上文了解数据库如何工作后，本节介绍如何将一个**关系模型**（基于表的数据模型）合理的转化为**数据表**和**关系表**，以及确定**主外键**的。这便是数据库设计理论基础，包括术语，函数依赖，范式等理论基础\n- [SQL DB - 关系型数据库设计流程](https://pdai.tech/md/db/sql/sql-db-theory-design.html)在上文知道如何设计表和健后，让我们再看看整个的**数据库设计的标准流程**吧，主要包括`需求分析`, `概念结构设计`, `逻辑结构设计` , `物理设计`, `实施阶段`和`运行和维护阶段`这6个阶段\n- [SQL DB - 数据库系统核心知识点](https://pdai.tech/md/db/sql/sql-db-theory.html)基于上篇数据库如何工作的基础之上，我们再来梳理下数据库系统中有哪些重要的知识点，包括：事务，并发一致性，封锁，隔离级别，多版本并发控制等\n\n---\n\n### SQL语言基础和进阶\n\n*相关文章*\n\n> **B. 完全掌握SQL语言**：在了解数据库基础之后，如下章节将重点阐述SQL语言相关的知识；主要顺序是：SQL语法->SQL语句练习->SQL题目进阶->SQL语句优化建议等。\n\n- [SQL语言 - SQL语法基础](https://pdai.tech/md/db/sql-lan/sql-lan.html)本文包含了所有SQL语言的基础语法，并用例子的方式向你展示\n- [SQL语言 - SQL语句练习](https://pdai.tech/md/db/sql-lan/sql-lan-pratice.html)在上文学习了SQL的基本语法以后，本文将通过最经典的“教师-学生-成绩”表来帮助你练习SQL。@pdai\n- [SQL语言 - SQL题目进阶](https://pdai.tech/md/db/sql-lan/sql-lan-leetcode.html)接下来，通过Leetcode上的SQL题目进行进阶吧\n- [SQL语言 - SQL语句优化](https://pdai.tech/md/db/sql-lan/sql-lan-optimize.html)最后，再总结一些SQL语句的优化建议\n\n---','https://images.unsplash.com/photo-1544383835-bda2bc66a55d?w=800','数据库基础和原理',NULL,0,NULL,'pdai-db-sql-sql-db','♥数据库基础和SQL知识体系详解♥ - 技术博客','暂无摘要',0,'PUBLISHED',7937,382,278,130,'2025-06-01 00:00:00','2025-06-01 00:00:00','2026-05-08 23:14:48',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`view_count`=VALUES(`view_count`),`like_count`=VALUES(`like_count`),`favorite_count`=VALUES(`favorite_count`),`comment_count`=VALUES(`comment_count`),`published_at`=VALUES(`published_at`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
