(300006,1,'SQL语言 - SQL语句练习','原文链接：https://pdai.tech/md/db/sql-lan/sql-lan-pratice.html','# SQL语言 - SQL语句练习\n\n> 在上文学习了SQL的基本语法以后，本文将通过最经典的“教师-学生-成绩”表来帮助你练习SQL。@pdai\n\n- SQL语言 - SQL语句练习构建如下表结构插入数据相关练习\n\n## 构建如下表结构\n\n> 还有一个Grade表，在如下的练习中体现\n\n![图片](/api/uploads/files/pdai/db-sql-learn-1-f5550dffb5.png)\n\n## 插入数据\n\n> 下面表SQL和相关测试数据是我Dump出来的\n\n```\n-- MySQL dump 10.13  Distrib 5.7.17, for macos10.12 (x86_64)\n--\n-- Host: localhost    Database: learn_sql_pdai_tech\n-- ------------------------------------------------------\n-- Server version\t5.7.28\n\n/*!40101 SET @OLD_CHARACTER_SET_CLIENT=@@CHARACTER_SET_CLIENT */;\n/*!40101 SET @OLD_CHARACTER_SET_RESULTS=@@CHARACTER_SET_RESULTS */;\n/*!40101 SET @OLD_COLLATION_CONNECTION=@@COLLATION_CONNECTION */;\n/*!40101 SET NAMES utf8 */;\n/*!40103 SET @OLD_TIME_ZONE=@@TIME_ZONE */;\n/*!40103 SET TIME_ZONE=\'+00:00\' */;\n/*!40014 SET @OLD_UNIQUE_CHECKS=@@UNIQUE_CHECKS, UNIQUE_CHECKS=0 */;\n/*!40014 SET @OLD_FOREIGN_KEY_CHECKS=@@FOREIGN_KEY_CHECKS, FOREIGN_KEY_CHECKS=0 */;\n/*!40101 SET @OLD_SQL_MODE=@@SQL_MODE, SQL_MODE=\'NO_AUTO_VALUE_ON_ZERO\' */;\n/*!40111 SET @OLD_SQL_NOTES=@@SQL_NOTES, SQL_NOTES=0 */;\n\n--\n-- Table structure for table `COURSE`\n--\n\nDROP TABLE IF EXISTS `COURSE`;\n/*!40101 SET @saved_cs_client     = @@character_set_client */;\n/*!40101 SET character_set_client = utf8 */;\nCREATE TABLE `COURSE` (\n  `CNO` varchar(5) NOT NULL,\n  `CNAME` varchar(10) NOT NULL,\n  `TNO` varchar(10) NOT NULL\n) ENGINE=InnoDB DEFAULT CHARSET=utf8;\n/*!40101 SET character_set_client = @saved_cs_client */;\n\n--\n-- Dumping data for table `COURSE`\n--\n\nLOCK TABLES `COURSE` WRITE;\n/*!40000 ALTER TABLE `COURSE` DISABLE KEYS */;\nINSERT INTO `COURSE` VALUES (\'3-105\',\'计算机导论\',\'825\'),(\'3-245\',\'操作系统\',\'804\'),(\'6-166\',\'数据电路\',\'856\'),(\'9-888\',\'高等数学\',\'100\');\n/*!40000 ALTER TABLE `COURSE` ENABLE KEYS */;\nUNLOCK TABLES;\n\n--\n-- Table structure for table `SCORE`\n--\n\nDROP TABLE IF EXISTS `SCORE`;\n/*!40101 SET @saved_cs_client     = @@character_set_client */;\n/*!40101 SET character_set_client = utf8 */;\nCREATE TABLE `SCORE` (\n  `SNO` varchar(3) NOT NULL,\n  `CNO` varchar(5) NOT NULL,\n  `DEGREE` decimal(10,1) NOT NULL\n) ENGINE=InnoDB DEFAULT CHARSET=utf8;\n/*!40101 SET character_set_client = @saved_cs_client */;\n\n--\n-- Dumping data for table `SCORE`\n--\n\nLOCK TABLES `SCORE` WRITE;\n/*!40000 ALTER TABLE `SCORE` DISABLE KEYS */;\nINSERT INTO `SCORE` VALUES (\'103\',\'3-245\',86.0),(\'105\',\'3-245\',75.0),(\'109\',\'3-245\',68.0),(\'103\',\'3-105\',92.0),(\'105\',\'3-105\',88.0),(\'109\',\'3-105\',76.0),(\'101\',\'3-105\',64.0),(\'107\',\'3-105\',91.0),(\'101\',\'6-166\',85.0),(\'107\',\'6-106\',79.0),(\'108\',\'3-105\',78.0),(\'108\',\'6-166\',81.0);\n/*!40000 ALTER TABLE `SCORE` ENABLE KEYS */;\nUNLOCK TABLES;\n\n--\n-- Table structure for table `STUDENT`\n--\n\nDROP TABLE IF EXISTS `STUDENT`;\n/*!40101 SET @saved_cs_client     = @@character_set_client */;\n/*!40101 SET character_set_client = utf8 */;\nCREATE TABLE `STUDENT` (\n  `SNO` varchar(3) NOT NULL,\n  `SNAME` varchar(4) NOT NULL,\n  `SSEX` varchar(2) NOT NULL,\n  `SBIRTHDAY` datetime DEFAULT NULL,\n  `CLASS` varchar(5) DEFAULT NULL\n) ENGINE=InnoDB DEFAULT CHARSET=utf8;\n/*!40101 SET character_set_client = @saved_cs_client */;\n\n--\n-- Dumping data for table `STUDENT`\n--\n\nLOCK TABLES `STUDENT` WRITE;\n/*!40000 ALTER TABLE `STUDENT` DISABLE KEYS */;\nINSERT INTO `STUDENT` VALUES (\'108\',\'曾华\',\'男\',\'1977-09-01 00:00:00\',\'95033\'),(\'105\',\'匡明\',\'男\',\'1975-10-02 00:00:00\',\'95031\'),(\'107\',\'王丽\',\'女\',\'1976-01-23 00:00:00\',\'95033\'),(\'101\',\'李军\',\'男\',\'1976-02-20 00:00:00\',\'95033\'),(\'109\',\'王芳\',\'女\',\'1975-02-10 00:00:00\',\'95031\'),(\'103\',\'陆君\',\'男\',\'1974-06-03 00:00:00\',\'95031\');\n/*!40000 ALTER TABLE `STUDENT` ENABLE KEYS */;\nUNLOCK TABLES;\n\n--\n-- Table structure for table `TEACHER`\n--\n\nDROP TABLE IF EXISTS `TEACHER`;\n/*!40101 SET @saved_cs_client     = @@character_set_client */;\n/*!40101 SET character_set_client = utf8 */;\nCREATE TABLE `TEACHER` (\n  `TNO` varchar(3) NOT NULL,\n  `TNAME` varchar(4) NOT NULL,\n  `TSEX` varchar(2) NOT NULL,\n  `TBIRTHDAY` datetime NOT NULL,\n  `PROF` varchar(6) DEFAULT NULL,\n  `DEPART` varchar(10) NOT NULL\n) ENGINE=InnoDB DEFAULT CHARSET=utf8;\n/*!40101 SET character_set_client = @saved_cs_client */;\n\n--\n-- Dumping data for table `TEACHER`\n--\n\nLOCK TABLES `TEACHER` WRITE;\n/*!40000 ALTER TABLE `TEACHER` DISABLE KEYS */;\nINSERT INTO `TEACHER` VALUES (\'804\',\'李诚\',\'男\',\'1958-12-02 00:00:00\',\'副教授\',\'计算机系\'),(\'856\',\'张旭\',\'男\',\'1969-03-12 00:00:00\',\'讲师\',\'电子工程系\'),(\'825\',\'王萍\',\'女\',\'1972-05-05 00:00:00\',\'助教\',\'计算机系\'),(\'831\',\'刘冰\',\'女\',\'1977-08-14 00:00:00\',\'助教\',\'电子工程系\');\n/*!40000 ALTER TABLE `TEACHER` ENABLE KEYS */;\nUNLOCK TABLES;\n/*!40103 SET TIME_ZONE=@OLD_TIME_ZONE */;\n\n/*!40101 SET SQL_MODE=@OLD_SQL_MODE */;\n/*!40014 SET FOREIGN_KEY_CHECKS=@OLD_FOREIGN_KEY_CHECKS */;\n/*!40014 SET UNIQUE_CHECKS=@OLD_UNIQUE_CHECKS */;\n/*!40101 SET CHARACTER_SET_CLIENT=@OLD_CHARACTER_SET_CLIENT */;\n/*!40101 SET CHARACTER_SET_RESULTS=@OLD_CHARACTER_SET_RESULTS */;\n/*!40101 SET COLLATION_CONNECTION=@OLD_COLLATION_CONNECTION */;\n/*!40111 SET SQL_NOTES=@OLD_SQL_NOTES */;\n\n-- Dump completed on 2020-02-06 18:18:25\n```\n\n## 相关练习\n\n- 1、 查询Student表中的所有记录的Sname、Ssex和Class列。\n\n```\nselect SNAME, SSEX, CLASS from STUDENT;\n```\n\n- 2、 查询教师所有的单位即不重复的Depart列。\n\n```\nselect distinct DEPART from TEACHER;\n```\n\n- 3、 查询Student表的所有记录。\n\n```\nselect * from STUDENT;\n```\n\n- 4、 查询Score表中成绩在60到80之间的所有记录。\n\n```\nselect *\nfrom SCORE\nwhere DEGREE > 60 and DEGREE < 80;\n```\n\n- 5、 查询Score表中成绩为85，86或88的记录。\n\n```\nselect *\nfrom SCORE\nwhere DEGREE = 85 or DEGREE = 86 or DEGREE = 88;\n```\n\n- 6、 查询Student表中“95031”班或性别为“女”的同学记录。\n\n```\nselect *\nfrom STUDENT\nwhere CLASS = \'95031\' or SSEX = \'女\';\n```\n\n- 7、 以Class降序查询Student表的所有记录。\n\n```\nselect *\nfrom STUDENT\norder by CLASS desc;\n```\n\n- 8、 以Cno升序、Degree降序查询Score表的所有记录。\n\n```\nselect *\nfrom SCORE\norder by CNO asc, DEGREE desc;\n```\n\n- 9、 查询“95031”班的学生人数。\n\n```\nselect count(*)\nfrom STUDENT\nwhere CLASS = \'95031\';\n```\n\n- 10、查询Score表中的最高分的学生学号和课程号。\n\n```\nselect\n  sno,\n  CNO\nfrom SCORE\nwhere DEGREE = (\n  select max(DEGREE)\n  from SCORE\n);\n```\n\n- 11、查询‘3-105’号课程的平均分。\n\n```\nselect avg(DEGREE)\nfrom SCORE\nwhere CNO = \'3-105\';\n```\n\n- 12、查询Score表中至少有5名学生选修的并以3开头的课程的平均分数。\n\n```\nselect\n  avg(DEGREE),\n  CNO\nfrom SCORE\nwhere cno like \'3%\'\ngroup by CNO\nhaving count(*) > 5;\n```\n\n- 13、查询最低分大于70，最高分小于90的Sno列。\n\n```\nselect SNO\nfrom SCORE\ngroup by SNO\nhaving min(DEGREE) > 70 and max(DEGREE) < 90;\n```\n\n- 14、查询所有学生的Sname、Cno和Degree列。\n\n```\nselect\n  SNAME,\n  CNO,\n  DEGREE\nfrom STUDENT, SCORE\nwhere STUDENT.SNO = SCORE.SNO;\n```\n\n- 15、查询所有学生的Sno、Cno和Degree列。\n\n```\nselect\n  SCORE.SNO,\n  CNO,\n  DEGREE\nfrom STUDENT, SCORE\nwhere STUDENT.SNO = SCORE.SNO;\n```\n\n- 16、查询所有学生的Sname、Cname和Degree列。\n\n```\nSELECT\n  A.SNAME,\n  B.CNAME,\n  C.DEGREE\nFROM STUDENT A\n  JOIN (COURSE B, SCORE C)\n    ON A.SNO = C.SNO AND B.CNO = C.CNO;\n```\n\n- 17、查询“95033”班所选课程的平均分。\n\n```\nselect avg(DEGREE)\nfrom SCORE\nwhere sno in (select SNO\n              from STUDENT\n              where CLASS = \'95033\');\n```\n\n- 18、假设使用如下命令建立了一个grade表:\n\n```\ncreate table grade (\n  low  numeric(3, 0),\n  upp  numeric(3),\n  rank char(1)\n);\ninsert into grade values (90, 100, \'A\');\ninsert into grade values (80, 89, \'B\');\ninsert into grade values (70, 79, \'C\');\ninsert into grade values (60, 69, \'D\');\ninsert into grade values (0, 59, \'E\');\n```\n\n- 现查询所有同学的Sno、Cno和rank列。\n\n```\nSELECT\n  A.SNO,\n  A.CNO,\n  B.RANK\nFROM SCORE A, grade B\nWHERE A.DEGREE BETWEEN B.LOW AND B.UPP\nORDER BY RANK;\n```\n\n- 19、查询选修“3-105”课程的成绩高于“109”号同学成绩的所有同学的记录。\n\n```\nselect *\nfrom SCORE\nwhere CNO = \'3-105\' and DEGREE > ALL (\n  select DEGREE\n  from SCORE\n  where SNO = \'109\'\n);\n```\n\n- 20、查询score中选学一门以上课程的同学中分数为非最高分成绩的学生记录\n\n```\nselect * from STUDENT where SNO\n  in (select SNO\n  from SCORE\n  where DEGREE < (select MAX(DEGREE) from SCORE)\n  group by SNO\n  having count(*) > 1);\n```\n\n- 21、查询成绩高于学号为“109”、课程号为“3-105”的成绩的所有记录。\n\n```\nselect *\nfrom SCORE\nwhere CNO = \'3-105\' and DEGREE > ALL (\n  select DEGREE\n  from SCORE\n  where SNO = \'109\'\n);\n```\n\n- 22、查询和学号为108的同学同年出生的所有学生的Sno、Sname和Sbirthday列。\n\n```\nselect\n  SNO,\n  SNAME,\n  SBIRTHDAY\nfrom STUDENT\nwhere year(SBIRTHDAY) = (\n  select year(SBIRTHDAY)\n  from STUDENT\n  where SNO = \'108\'\n);\n```\n\n- 23、查询“张旭“教师任课的学生成绩。\n\n```\nselect *\nfrom SCORE\nwhere cno = (\n  select CNO\n  from COURSE\n    inner join TEACHER on COURSE.TNO = TEACHER.TNO and TNAME = \'张旭\'\n);\n```\n\n- 24、查询选修某课程的同学人数多于5人的教师姓名。\n\n```\nselect TNAME\nfrom TEACHER\nwhere TNO = (\n  select TNO\n  from COURSE\n  where CNO = (select CNO\n               from SCORE\n               group by CNO\n               having count(SNO) > 5)\n);\n```\n\n- 25、查询95033班和95031班全体学生的记录。\n\n```\nselect *\nfrom STUDENT\nwhere CLASS in (\'95033\', \'95031\');\n```\n\n- 26、查询存在有85分以上成绩的课程Cno.\n\n```\nselect cno\nfrom SCORE\ngroup by CNO\nhaving MAX(DEGREE) > 85;\n```\n\n- 27、查询出“计算机系“教师所教课程的成绩表。\n\n```\nselect *\nfrom SCORE\nwhere CNO in (select CNO\n              from TEACHER, COURSE\n              where DEPART = \'计算机系\' and COURSE.TNO = TEACHER.TNO);\n```\n\n- 28、查询“计算机系”与“电子工程系“不同职称的教师的Tname和Prof\n\n```\nselect\n  tname,\n  prof\nfrom TEACHER\nwhere depart = \'计算机系\' and prof not in (\n  select prof\n  from TEACHER\n  where depart = \'电子工程系\'\n);\n```\n\n- 29、查询选修编号为“3-105“课程且成绩至少高于选修编号为“3-245”的同学的Cno、Sno和Degree,并按Degree从高到低次序排序。\n\n```\nselect\n  CNO,\n  SNO,\n  DEGREE\nfrom SCORE\nwhere CNO = \'3-105\' and DEGREE > any (\n  select DEGREE\n  from SCORE\n  where CNO = \'3-245\'\n)\norder by DEGREE desc;\n```\n\n- 30、查询选修编号为“3-105”且成绩高于选修编号为“3-245”课程的同学的Cno、Sno和Degree.\n\n```\nSELECT *\nFROM SCORE\nWHERE CNO = \'3-105\' AND DEGREE > ALL (\n  SELECT DEGREE\n  FROM SCORE\n  WHERE CNO = \'3-245\'\n)\nORDER by DEGREE desc;\n```\n\n- 31、查询所有教师和同学的name、sex和birthday.\n\n```\nselect\n  TNAME     name,\n  TSEX      sex,\n  TBIRTHDAY birthday\nfrom TEACHER\nunion\nselect\n  sname     name,\n  SSEX      sex,\n  SBIRTHDAY birthday\nfrom STUDENT;\n```\n\n- 32、查询所有“女”教师和“女”同学的name、sex和birthday.\n\n```\nselect\n  TNAME     name,\n  TSEX      sex,\n  TBIRTHDAY birthday\nfrom TEACHER\nwhere TSEX = \'女\'\nunion\nselect\n  sname     name,\n  SSEX      sex,\n  SBIRTHDAY birthday\nfrom STUDENT\nwhere SSEX = \'女\';\n```\n\n- 33、查询成绩比该课程平均成绩低的同学的成绩表。\n\n```\nSELECT A.*\nFROM SCORE A\nWHERE DEGREE < (SELECT AVG(DEGREE)\n                FROM SCORE B\n                WHERE A.CNO = B.CNO);\n```\n\n- 34、查询所有任课教师的Tname和Depart.\n\n```\nselect\n  TNAME,\n  DEPART\nfrom TEACHER a\nwhere exists(select *\n             from COURSE b\n             where a.TNO = b.TNO);\n```\n\n- 35、查询所有未讲课的教师的Tname和Depart.\n\n```\nselect\n  TNAME,\n  DEPART\nfrom TEACHER a\nwhere tno not in (select tno\n                  from COURSE);\n```\n\n- 36、查询至少有2名男生的班号。\n\n```\nselect CLASS\nfrom STUDENT\nwhere SSEX = \'男\'\ngroup by CLASS\nhaving count(SSEX) > 1;\n```\n\n- 37、查询Student表中不姓“王”的同学记录。\n\n```\nselect *\nfrom STUDENT\nwhere SNAME not like "王%";\n```\n\n- 38、查询Student表中每个学生的姓名和年龄。\n\n```\nselect\n  SNAME,\n  year(now()) - year(SBIRTHDAY)\nfrom STUDENT;\n```\n\n- 39、查询Student表中最大和最小的Sbirthday日期值。\n\n```\nselect min(SBIRTHDAY) birthday\nfrom STUDENT\nunion\nselect max(SBIRTHDAY) birthday\nfrom STUDENT;\n```\n\n- 40、以班号和年龄从大到小的顺序查询Student表中的全部记录。\n\n```\nselect *\nfrom STUDENT\norder by CLASS desc, year(now()) - year(SBIRTHDAY) desc;\n```\n\n- 41、查询“男”教师及其所上的课程。\n\n```\nselect *\nfrom TEACHER, COURSE\nwhere TSEX = \'男\' and COURSE.TNO = TEACHER.TNO;\n```\n\n- 42、查询最高分同学的Sno、Cno和Degree列。\n\n```\nselect\n  sno,\n  CNO,\n  DEGREE\nfrom SCORE\nwhere DEGREE = (select max(DEGREE)\n                from SCORE);\n```\n\n- 43、查询和“李军”同性别的所有同学的Sname.\n\n```\nselect sname\nfrom STUDENT\nwhere SSEX = (select SSEX\n              from STUDENT\n              where SNAME = \'李军\');\n```\n\n- 44、查询和“李军”同性别并同班的同学Sname.\n\n```\nselect sname\nfrom STUDENT\nwhere (SSEX, CLASS) = (select\n                         SSEX,\n                         CLASS\n                       from STUDENT\n                       where SNAME = \'李军\');\n```\n\n- 45、查询所有选修“计算机导论”课程的“男”同学的成绩表\n\n```\nselect *\nfrom SCORE, STUDENT\nwhere SCORE.SNO = STUDENT.SNO and SSEX = \'男\' and CNO = (\n  select CNO\n  from COURSE\n  where CNAME = \'计算机导论\');\n```\n\n- 46、使用游标方式来同时查询每位同学的名字，他所选课程及成绩。\n\n```\ndeclare\n cursor student_cursor is\n  select S.SNO,S.SNAME,C.CNAME,SC.DEGREE as DEGREE\n  from STUDENT S, COURSE C, SCORE SC\n  where S.SNO=SC.SNO\n  and SC.CNO=C.CNO;\n\n  student_row student_cursor%ROWTYPE;\n\nbegin\n  open student_cursor;\n   loop\n    fetch student_cursor INTO student_row;\n    exit when student_cursor%NOTFOUND;\n     dbms_output.put_line( student_row.SNO || \'\' || \n\nstudent_row.SNAME|| \'\' || student_row.CNAME || \'\' ||\n\nstudent_row.DEGREE);\n   end loop;\n  close student_cursor;\nEND;\n/ \n```\n\n- 47、 声明触发器指令，每当有同学转换班级时执行触发器显示当前和之前所在班级。\n\n```\nCREATE OR REPLACE TRIGGER display_class_changes \nAFTER DELETE OR INSERT OR UPDATE ON student \nFOR EACH ROW \nWHEN (NEW.sno > 0) \n\nBEGIN \n   \n   dbms_output.put_line(\'Old class: \' || :OLD.class); \n   dbms_output.put_line(\'New class: \' || :NEW.class); \nEND; \n/ \n\nUpdate student\nset class=95031\nwhere sno=109;\n```\n\n- 48、 删除已设置的触发器指令\n\n```\nDROP TRIGGER display_class_changes;\n```\n\n---\n\n原文链接：https://pdai.tech/md/db/sql-lan/sql-lan-pratice.html','https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=800','SQL 语言',NULL,0,NULL,'pdai-db-sql-lan-sql-lan-pratice','SQL语言 - SQL语句练习 - 技术博客','原文链接：https://pdai.tech/md/db/sql-lan/sql-lan-pratice.html',0,'PUBLISHED',4394,466,136,62,'2025-06-07 00:00:00','2025-06-07 00:00:00','2026-05-08 23:14:48',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`view_count`=VALUES(`view_count`),`like_count`=VALUES(`like_count`),`favorite_count`=VALUES(`favorite_count`),`comment_count`=VALUES(`comment_count`),`published_at`=VALUES(`published_at`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES
(300007,2,'SQL语言 - SQL题目进阶','https://leetcode.com/problems/big-countries/description/ 查找面积超过 3,000,000 或者人口数超过 25,000,000 的国家。 https://leetcode.com/problems/swap-salary/description/ 只用一个 SQL 查询，将 sex 字段反转。','# SQL语言 - SQL题目进阶\n\n> 接下来，通过Leetcode上的SQL题目进行进阶吧。@pdai\nGFM-TOC\n\n- SQL语言 - SQL题目进阶相关题目595. Big CountriesDescriptionSQL SchemaSolution627. Swap SalaryDescriptionSQL SchemaSolution620. Not Boring MoviesDescriptionSQL SchemaSolution596. Classes More Than 5 StudentsDescriptionSQL SchemaSolution182. Duplicate EmailsDescriptionSQL SchemaSolution196. Delete Duplicate EmailsDescriptionSQL SchemaSolution175. Combine Two TablesDescriptionSQL SchemaSolution181. Employees Earning More Than Their ManagersDescriptionSQL SchemaSolution183. Customers Who Never OrderDescriptionSQL SchemaSolution184. Department Highest SalaryDescriptionSQL SchemaSolution176. Second Highest SalaryDescriptionSQL SchemaSolution177. Nth Highest SalaryDescriptionSQL SchemaSolution178. Rank ScoresDescriptionSQL SchemaSolution180. Consecutive NumbersDescriptionSQL SchemaSolution626. Exchange SeatsDescriptionSQL SchemaSolution\nGFM-TOC\n\n## 相关题目\n\n### 595. Big Countries\n\nhttps://leetcode.com/problems/big-countries/description/\n\n#### Description\n\n```\n+-----------------+------------+------------+--------------+---------------+\n| name            | continent  | area       | population   | gdp           |\n+-----------------+------------+------------+--------------+---------------+\n| Afghanistan     | Asia       | 652230     | 25500100     | 20343000      |\n| Albania         | Europe     | 28748      | 2831741      | 12960000      |\n| Algeria         | Africa     | 2381741    | 37100000     | 188681000     |\n| Andorra         | Europe     | 468        | 78115        | 3712000       |\n| Angola          | Africa     | 1246700    | 20609294     | 100990000     |\n+-----------------+------------+------------+--------------+---------------+\n```\n\n查找面积超过 3,000,000 或者人口数超过 25,000,000 的国家。\n\n```\n+--------------+-------------+--------------+\n| name         | population  | area         |\n+--------------+-------------+--------------+\n| Afghanistan  | 25500100    | 652230       |\n| Algeria      | 37100000    | 2381741      |\n+--------------+-------------+--------------+\n```\n\n#### SQL Schema\n\n```\nDROP TABLE\nIF\n    EXISTS World;\nCREATE TABLE World ( NAME VARCHAR ( 255 ), continent VARCHAR ( 255 ), area INT, population INT, gdp INT );\nINSERT INTO World ( NAME, continent, area, population, gdp )\nVALUES\n    ( \'Afghanistan\', \'Asia\', \'652230\', \'25500100\', \'203430000\' ),\n    ( \'Albania\', \'Europe\', \'28748\', \'2831741\', \'129600000\' ),\n    ( \'Algeria\', \'Africa\', \'2381741\', \'37100000\', \'1886810000\' ),\n    ( \'Andorra\', \'Europe\', \'468\', \'78115\', \'37120000\' ),\n    ( \'Angola\', \'Africa\', \'1246700\', \'20609294\', \'1009900000\' );\n```\n\n#### Solution\n\n```\nSELECT name,\n    population,\n    area\nFROM\n    World\nWHERE\n    area > 3000000\n    OR population > 25000000;\n```\n\n### 627. Swap Salary\n\nhttps://leetcode.com/problems/swap-salary/description/\n\n#### Description\n\n```\n| id | name | sex | salary |\n|----|------|-----|--------|\n| 1  | A    | m   | 2500   |\n| 2  | B    | f   | 1500   |\n| 3  | C    | m   | 5500   |\n| 4  | D    | f   | 500    |\n```\n\n只用一个 SQL 查询，将 sex 字段反转。\n\n```\n| id | name | sex | salary |\n|----|------|-----|--------|\n| 1  | A    | f   | 2500   |\n| 2  | B    | m   | 1500   |\n| 3  | C    | f   | 5500   |\n| 4  | D    | m   | 500    |\n```\n\n#### SQL Schema\n\n```\nDROP TABLE\nIF\n    EXISTS salary;\nCREATE TABLE salary ( id INT, NAME VARCHAR ( 100 ), sex CHAR ( 1 ), salary INT );\nINSERT INTO salary ( id, NAME, sex, salary )\nVALUES\n    ( \'1\', \'A\', \'m\', \'2500\' ),\n    ( \'2\', \'B\', \'f\', \'1500\' ),\n    ( \'3\', \'C\', \'m\', \'5500\' ),\n    ( \'4\', \'D\', \'f\', \'500\' );\n```\n\n#### Solution\n\n```\nUPDATE salary\nSET sex = CHAR ( ASCII(sex) ^ ASCII( \'m\' ) ^ ASCII( \'f\' ) );\n```\n\n### 620. Not Boring Movies\n\nhttps://leetcode.com/problems/not-boring-movies/description/\n\n#### Description\n\n```\n+---------+-----------+--------------+-----------+\n|   id    | movie     |  description |  rating   |\n+---------+-----------+--------------+-----------+\n|   1     | War       |   great 3D   |   8.9     |\n|   2     | Science   |   fiction    |   8.5     |\n|   3     | irish     |   boring     |   6.2     |\n|   4     | Ice song  |   Fantacy    |   8.6     |\n|   5     | House card|   Interesting|   9.1     |\n+---------+-----------+--------------+-----------+\n```\n\n查找 id 为奇数，并且 description 不是 boring 的电影，按 rating 降序。\n\n```\n+---------+-----------+--------------+-----------+\n|   id    | movie     |  description |  rating   |\n+---------+-----------+--------------+-----------+\n|   5     | House card|   Interesting|   9.1     |\n|   1     | War       |   great 3D   |   8.9     |\n+---------+-----------+--------------+-----------+\n```\n\n#### SQL Schema\n\n```\nDROP TABLE\nIF\n    EXISTS cinema;\nCREATE TABLE cinema ( id INT, movie VARCHAR ( 255 ), description VARCHAR ( 255 ), rating FLOAT ( 2, 1 ) );\nINSERT INTO cinema ( id, movie, description, rating )\nVALUES\n    ( 1, \'War\', \'great 3D\', 8.9 ),\n    ( 2, \'Science\', \'fiction\', 8.5 ),\n    ( 3, \'irish\', \'boring\', 6.2 ),\n    ( 4, \'Ice song\', \'Fantacy\', 8.6 ),\n    ( 5, \'House card\', \'Interesting\', 9.1 );\n```\n\n#### Solution\n\n```\nSELECT\n    *\nFROM\n    cinema\nWHERE\n    id % 2 = 1\n    AND description != \'boring\'\nORDER BY\n    rating DESC;\n```\n\n### 596. Classes More Than 5 Students\n\nhttps://leetcode.com/problems/classes-more-than-5-students/description/\n\n#### Description\n\n```\n+---------+------------+\n| student | class      |\n+---------+------------+\n| A       | Math       |\n| B       | English    |\n| C       | Math       |\n| D       | Biology    |\n| E       | Math       |\n| F       | Computer   |\n| G       | Math       |\n| H       | Math       |\n| I       | Math       |\n+---------+------------+\n```\n\n查找有五名及以上 student 的 class。\n\n```\n+---------+\n| class   |\n+---------+\n| Math    |\n+---------+\n```\n\n#### SQL Schema\n\n```\nDROP TABLE\nIF\n    EXISTS courses;\nCREATE TABLE courses ( student VARCHAR ( 255 ), class VARCHAR ( 255 ) );\nINSERT INTO courses ( student, class )\nVALUES\n    ( \'A\', \'Math\' ),\n    ( \'B\', \'English\' ),\n    ( \'C\', \'Math\' ),\n    ( \'D\', \'Biology\' ),\n    ( \'E\', \'Math\' ),\n    ( \'F\', \'Computer\' ),\n    ( \'G\', \'Math\' ),\n    ( \'H\', \'Math\' ),\n    ( \'I\', \'Math\' );\n```\n\n#### Solution\n\n```\nSELECT\n    class\nFROM\n    courses\nGROUP BY\n    class\nHAVING\n    count( DISTINCT student ) >= 5;\n```\n\n### 182. Duplicate Emails\n\nhttps://leetcode.com/problems/duplicate-emails/description/\n\n#### Description\n\n邮件地址表:\n\n```\n+----+---------+\n| Id | Email   |\n+----+---------+\n| 1  | a@b.com |\n| 2  | c@d.com |\n| 3  | a@b.com |\n+----+---------+\n```\n\n查找重复的邮件地址:\n\n```\n+---------+\n| Email   |\n+---------+\n| a@b.com |\n+---------+\n```\n\n#### SQL Schema\n\n```\nDROP TABLE\nIF\n    EXISTS Person;\nCREATE TABLE Person ( Id INT, Email VARCHAR ( 255 ) );\nINSERT INTO Person ( Id, Email )\nVALUES\n    ( 1, \'a@b.com\' ),\n    ( 2, \'c@d.com\' ),\n    ( 3, \'a@b.com\' );\n```\n\n#### Solution\n\n```\nSELECT\n    Email\nFROM\n    Person\nGROUP BY\n    Email\nHAVING\n    COUNT( * ) >= 2;\n```\n\n### 196. Delete Duplicate Emails\n\nhttps://leetcode.com/problems/delete-duplicate-emails/description/\n\n#### Description\n\n邮件地址表:\n\n```\n+----+---------+\n| Id | Email   |\n+----+---------+\n| 1  | a@b.com |\n| 2  | c@d.com |\n| 3  | a@b.com |\n+----+---------+\n```\n\n删除重复的邮件地址:\n\n```\n+----+------------------+\n| Id | Email            |\n+----+------------------+\n| 1  | john@example.com |\n| 2  | bob@example.com  |\n+----+------------------+\n```\n\n#### SQL Schema\n\n与 182 相同。\n\n#### Solution\n\n连接:\n\n```\nDELETE p1\nFROM\n    Person p1,\n    Person p2\nWHERE\n    p1.Email = p2.Email\n    AND p1.Id > p2.Id\n```\n\n子查询:\n\n```\nDELETE\nFROM\n    Person\nWHERE\n    id NOT IN ( SELECT id FROM ( SELECT min( id ) AS id FROM Person GROUP BY email ) AS m );\n```\n\n应该注意的是上述解法额外嵌套了一个 SELECT 语句，如果不这么做，会出现错误: You can\'t specify target table \'Person\' for update in FROM clause。以下演示了这种错误解法。\n\n```\nDELETE\nFROM\n    Person\nWHERE\n    id NOT IN ( SELECT min( id ) AS id FROM Person GROUP BY email );\n```\n\n参考: [pMySQL Error 1093 - Can\'t specify target table for update in FROM clause在新窗口打开](https://stackoverflow.com/questions/45494/mysql-error-1093-cant-specify-target-table-for-update-in-from-clause)\n\n### 175. Combine Two Tables\n\nhttps://leetcode.com/problems/combine-two-tables/description/\n\n#### Description\n\nPerson 表:\n\n```\n+-------------+---------+\n| Column Name | Type    |\n+-------------+---------+\n| PersonId    | int     |\n| FirstName   | varchar |\n| LastName    | varchar |\n+-------------+---------+\nPersonId is the primary key column for this table.\n```\n\nAddress 表:\n\n```\n+-------------+---------+\n| Column Name | Type    |\n+-------------+---------+\n| AddressId   | int     |\n| PersonId    | int     |\n| City        | varchar |\n| State       | varchar |\n+-------------+---------+\nAddressId is the primary key column for this table.\n```\n\n查找 FirstName, LastName, City, State 数据，而不管一个用户有没有填地址信息。\n\n#### SQL Schema\n\n```\nDROP TABLE\nIF\n    EXISTS Person;\nCREATE TABLE Person ( PersonId INT, FirstName VARCHAR ( 255 ), LastName VARCHAR ( 255 ) );\nDROP TABLE\nIF\n    EXISTS Address;\nCREATE TABLE Address ( AddressId INT, PersonId INT, City VARCHAR ( 255 ), State VARCHAR ( 255 ) );\nINSERT INTO Person ( PersonId, LastName, FirstName )\nVALUES\n    ( 1, \'Wang\', \'Allen\' );\nINSERT INTO Address ( AddressId, PersonId, City, State )\nVALUES\n    ( 1, 2, \'New York City\', \'New York\' );\n```\n\n#### Solution\n\n使用左外连接。\n\n```\nSELECT\n    FirstName,\n    LastName,\n    City,\n    State\nFROM\n    Person P\n    LEFT JOIN Address A\n    ON P.PersonId = A.PersonId;\n```\n\n### 181. Employees Earning More Than Their Managers\n\nhttps://leetcode.com/problems/employees-earning-more-than-their-managers/description/\n\n#### Description\n\nEmployee 表:\n\n```\n+----+-------+--------+-----------+\n| Id | Name  | Salary | ManagerId |\n+----+-------+--------+-----------+\n| 1  | Joe   | 70000  | 3         |\n| 2  | Henry | 80000  | 4         |\n| 3  | Sam   | 60000  | NULL      |\n| 4  | Max   | 90000  | NULL      |\n+----+-------+--------+-----------+\n```\n\n查找薪资大于其经理薪资的员工信息。\n\n#### SQL Schema\n\n```\nDROP TABLE\nIF\n    EXISTS Employee;\nCREATE TABLE Employee ( Id INT, NAME VARCHAR ( 255 ), Salary INT, ManagerId INT );\nINSERT INTO Employee ( Id, NAME, Salary, ManagerId )\nVALUES\n    ( 1, \'Joe\', 70000, 3 ),\n    ( 2, \'Henry\', 80000, 4 ),\n    ( 3, \'Sam\', 60000, NULL ),\n    ( 4, \'Max\', 90000, NULL );\n```\n\n#### Solution\n\n```\nSELECT\n    E1.NAME AS Employee\nFROM\n    Employee E1\n    INNER JOIN Employee E2\n    ON E1.ManagerId = E2.Id\n    AND E1.Salary > E2.Salary;\n```\n\n### 183. Customers Who Never Order\n\nhttps://leetcode.com/problems/customers-who-never-order/description/\n\n#### Description\n\nCurstomers 表:\n\n```\n+----+-------+\n| Id | Name  |\n+----+-------+\n| 1  | Joe   |\n| 2  | Henry |\n| 3  | Sam   |\n| 4  | Max   |\n+----+-------+\n```\n\nOrders 表:\n\n```\n+----+------------+\n| Id | CustomerId |\n+----+------------+\n| 1  | 3          |\n| 2  | 1          |\n+----+------------+\n```\n\n查找没有订单的顾客信息:\n\n```\n+-----------+\n| Customers |\n+-----------+\n| Henry     |\n| Max       |\n+-----------+\n```\n\n#### SQL Schema\n\n```\nDROP TABLE\nIF\n    EXISTS Customers;\nCREATE TABLE Customers ( Id INT, NAME VARCHAR ( 255 ) );\nDROP TABLE\nIF\n    EXISTS Orders;\nCREATE TABLE Orders ( Id INT, CustomerId INT );\nINSERT INTO Customers ( Id, NAME )\nVALUES\n    ( 1, \'Joe\' ),\n    ( 2, \'Henry\' ),\n    ( 3, \'Sam\' ),\n    ( 4, \'Max\' );\nINSERT INTO Orders ( Id, CustomerId )\nVALUES\n    ( 1, 3 ),\n    ( 2, 1 );\n```\n\n#### Solution\n\n左外链接\n\n```\nSELECT\n    C.Name AS Customers\nFROM\n    Customers C\n    LEFT JOIN Orders O\n    ON C.Id = O.CustomerId\nWHERE\n    O.CustomerId IS NULL;\n```\n\n子查询\n\n```\nSELECT\n    Name AS Customers\nFROM\n    Customers\nWHERE\n    Id NOT IN ( SELECT CustomerId FROM Orders );\n```\n\n### 184. Department Highest Salary\n\nhttps://leetcode.com/problems/department-highest-salary/description/\n\n#### Description\n\nEmployee 表:\n\n```\n+----+-------+--------+--------------+\n| Id | Name  | Salary | DepartmentId |\n+----+-------+--------+--------------+\n| 1  | Joe   | 70000  | 1            |\n| 2  | Henry | 80000  | 2            |\n| 3  | Sam   | 60000  | 2            |\n| 4  | Max   | 90000  | 1            |\n+----+-------+--------+--------------+\n```\n\nDepartment 表:\n\n```\n+----+----------+\n| Id | Name     |\n+----+----------+\n| 1  | IT       |\n| 2  | Sales    |\n+----+----------+\n```\n\n查找一个 Department 中收入最高者的信息:\n\n```\n+------------+----------+--------+\n| Department | Employee | Salary |\n+------------+----------+--------+\n| IT         | Max      | 90000  |\n| Sales      | Henry    | 80000  |\n+------------+----------+--------+\n```\n\n#### SQL Schema\n\n```\nDROP TABLE IF EXISTS Employee;\nCREATE TABLE Employee ( Id INT, NAME VARCHAR ( 255 ), Salary INT, DepartmentId INT );\nDROP TABLE IF EXISTS Department;\nCREATE TABLE Department ( Id INT, NAME VARCHAR ( 255 ) );\nINSERT INTO Employee ( Id, NAME, Salary, DepartmentId )\nVALUES\n    ( 1, \'Joe\', 70000, 1 ),\n    ( 2, \'Henry\', 80000, 2 ),\n    ( 3, \'Sam\', 60000, 2 ),\n    ( 4, \'Max\', 90000, 1 );\nINSERT INTO Department ( Id, NAME )\nVALUES\n    ( 1, \'IT\' ),\n    ( 2, \'Sales\' );\n```\n\n#### Solution\n\n创建一个临时表，包含了部门员工的最大薪资。可以对部门进行分组，然后使用 MAX() 汇总函数取得最大薪资。\n\n之后使用连接找到一个部门中薪资等于临时表中最大薪资的员工。\n\n```\nSELECT\n    D.NAME Department,\n    E.NAME Employee,\n    E.Salary\nFROM\n    Employee E,\n    Department D,\n    ( SELECT DepartmentId, MAX( Salary ) Salary FROM Employee GROUP BY DepartmentId ) M\nWHERE\n    E.DepartmentId = D.Id\n    AND E.DepartmentId = M.DepartmentId\n    AND E.Salary = M.Salary;\n```\n\n### 176. Second Highest Salary\n\nhttps://leetcode.com/problems/second-highest-salary/description/\n\n#### Description\n\n```\n+----+--------+\n| Id | Salary |\n+----+--------+\n| 1  | 100    |\n| 2  | 200    |\n| 3  | 300    |\n+----+--------+\n```\n\n查找工资第二高的员工。\n\n```\n+---------------------+\n| SecondHighestSalary |\n+---------------------+\n| 200                 |\n+---------------------+\n```\n\n没有找到返回 null 而不是不返回数据。\n\n#### SQL Schema\n\n```\nDROP TABLE\nIF\n    EXISTS Employee;\nCREATE TABLE Employee ( Id INT, Salary INT );\nINSERT INTO Employee ( Id, Salary )\nVALUES\n    ( 1, 100 ),\n    ( 2, 200 ),\n    ( 3, 300 );\n```\n\n#### Solution\n\n为了在没有查找到数据时返回 null，需要在查询结果外面再套一层 SELECT。\n\n```\nSELECT\n    ( SELECT DISTINCT Salary FROM Employee ORDER BY Salary DESC LIMIT 1, 1 ) SecondHighestSalary;\n```\n\n### 177. Nth Highest Salary\n\n#### Description\n\n查找工资第 N 高的员工。\n\n#### SQL Schema\n\n同 176。\n\n#### Solution\n\n```\nCREATE FUNCTION getNthHighestSalary ( N INT ) RETURNS INT BEGIN\n\nSET N = N - 1;\nRETURN ( SELECT ( SELECT DISTINCT Salary FROM Employee ORDER BY Salary DESC LIMIT N, 1 ) );\n\nEND\n```\n\n### 178. Rank Scores\n\nhttps://leetcode.com/problems/rank-scores/description/\n\n#### Description\n\n得分表:\n\n```\n+----+-------+\n| Id | Score |\n+----+-------+\n| 1  | 3.50  |\n| 2  | 3.65  |\n| 3  | 4.00  |\n| 4  | 3.85  |\n| 5  | 4.00  |\n| 6  | 3.65  |\n+----+-------+\n```\n\n将得分排序，并统计排名。\n\n```\n+-------+------+\n| Score | Rank |\n+-------+------+\n| 4.00  | 1    |\n| 4.00  | 1    |\n| 3.85  | 2    |\n| 3.65  | 3    |\n| 3.65  | 3    |\n| 3.50  | 4    |\n+-------+------+\n```\n\n#### SQL Schema\n\n```\nDROP TABLE\nIF\n    EXISTS Scores;\nCREATE TABLE Scores ( Id INT, Score DECIMAL ( 3, 2 ) );\nINSERT INTO Scores ( Id, Score )\nVALUES\n    ( 1, 3.5 ),\n    ( 2, 3.65 ),\n    ( 3, 4.0 ),\n    ( 4, 3.85 ),\n    ( 5, 4.0 ),\n    ( 6, 3.65 );\n```\n\n#### Solution\n\n```\nSELECT\n    S1.score,\n    COUNT( DISTINCT S2.score ) Rank\nFROM\n    Scores S1\n    INNER JOIN Scores S2\n    ON S1.score <= S2.score\nGROUP BY\n    S1.id\nORDER BY\n    S1.score DESC;\n```\n\n### 180. Consecutive Numbers\n\nhttps://leetcode.com/problems/consecutive-numbers/description/\n\n#### Description\n\n数字表:\n\n```\n+----+-----+\n| Id | Num |\n+----+-----+\n| 1  |  1  |\n| 2  |  1  |\n| 3  |  1  |\n| 4  |  2  |\n| 5  |  1  |\n| 6  |  2  |\n| 7  |  2  |\n+----+-----+\n```\n\n查找连续出现三次的数字。\n\n```\n+-----------------+\n| ConsecutiveNums |\n+-----------------+\n| 1               |\n+-----------------+\n```\n\n#### SQL Schema\n\n```\nDROP TABLE\nIF\n    EXISTS LOGS;\nCREATE TABLE LOGS ( Id INT, Num INT );\nINSERT INTO LOGS ( Id, Num )\nVALUES\n    ( 1, 1 ),\n    ( 2, 1 ),\n    ( 3, 1 ),\n    ( 4, 2 ),\n    ( 5, 1 ),\n    ( 6, 2 ),\n    ( 7, 2 );\n```\n\n#### Solution\n\n```\nSELECT\n    DISTINCT L1.num ConsecutiveNums\nFROM\n    Logs L1,\n    Logs L2,\n    Logs L3\nWHERE L1.id = l2.id - 1\n    AND L2.id = L3.id - 1\n    AND L1.num = L2.num\n    AND l2.num = l3.num;\n```\n\n### 626. Exchange Seats\n\nhttps://leetcode.com/problems/exchange-seats/description/\n\n#### Description\n\nseat 表存储着座位对应的学生。\n\n```\n+---------+---------+\n|    id   | student |\n+---------+---------+\n|    1    | Abbot   |\n|    2    | Doris   |\n|    3    | Emerson |\n|    4    | Green   |\n|    5    | Jeames  |\n+---------+---------+\n```\n\n要求交换相邻座位的两个学生，如果最后一个座位是奇数，那么不交换这个座位上的学生。\n\n```\n+---------+---------+\n|    id   | student |\n+---------+---------+\n|    1    | Doris   |\n|    2    | Abbot   |\n|    3    | Green   |\n|    4    | Emerson |\n|    5    | Jeames  |\n+---------+---------+\n```\n\n#### SQL Schema\n\n```\nDROP TABLE\nIF\n    EXISTS seat;\nCREATE TABLE seat ( id INT, student VARCHAR ( 255 ) );\nINSERT INTO seat ( id, student )\nVALUES\n    ( \'1\', \'Abbot\' ),\n    ( \'2\', \'Doris\' ),\n    ( \'3\', \'Emerson\' ),\n    ( \'4\', \'Green\' ),\n    ( \'5\', \'Jeames\' );\n```\n\n#### Solution\n\n使用多个 union。\n\n```\nSELECT\n    s1.id - 1 AS id,\n    s1.student\nFROM\n    seat s1\nWHERE\n    s1.id MOD 2 = 0 UNION\nSELECT\n    s2.id + 1 AS id,\n    s2.student\nFROM\n    seat s2\nWHERE\n    s2.id MOD 2 = 1\n    AND s2.id != ( SELECT max( s3.id ) FROM seat s3 ) UNION\nSELECT\n    s4.id AS id,\n    s4.student\nFROM\n    seat s4\nWHERE\n    s4.id MOD 2 = 1\n    AND s4.id = ( SELECT max( s5.id ) FROM seat s5 )\nORDER BY\n    id;\n```\n\n---\n\n原文链接：https://pdai.tech/md/db/sql-lan/sql-lan-leetcode.html','https://images.unsplash.com/photo-1544383835-bda2bc66a55d?w=800','SQL 语言',NULL,0,NULL,'pdai-db-sql-lan-sql-lan-leetcode','SQL语言 - SQL题目进阶 - 技术博客','https://leetcode.com/problems/big-countries/description/ 查找面积超过 3,000,000 或者人口数超过 25,000,000 的国家。 https://leetcode.com/p...',0,'PUBLISHED',3380,79,58,45,'2025-06-22 00:00:00','2025-06-22 00:00:00','2026-05-08 23:14:48',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`view_count`=VALUES(`view_count`),`like_count`=VALUES(`like_count`),`favorite_count`=VALUES(`favorite_count`),`comment_count`=VALUES(`comment_count`),`published_at`=VALUES(`published_at`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
