(300051,2,'Mongo入门 - 基本使用：Java API','例子请参考 mongo-java-driver 例子在新窗口打开http://mongodb.github.io/mongo-java-driver/3.12/driver/getting-started/quick-start/ 原文链接：https://pdai.tech/md/db/nosql-mongo/mongo-x-usage-4.html','# Mongo入门 - 基本使用：Java API\n\n> 本文为低优先级，只是向你介绍下MongoDB提供的原生的JavaAPI；而大多数公司使用Spring框架，会使用Spring Data对MongoDB原生API的封装，比如JPA，MongoTemplate等。@pdai\n\n- Mongo入门 - 基本使用：Java APIMongoDB Driver代码测试\n\n## MongoDB Driver\n\n```\n<!-- https://mvnrepository.com/artifact/org.mongodb/mongo-java-driver -->\n<dependency>\n    <groupId>org.mongodb</groupId>\n    <artifactId>mongo-java-driver</artifactId>\n    <version>3.12.6</version>\n</dependency>\n```\n\n## 代码测试\n\n例子请参考 [mongo-java-driver 例子在新窗口打开](http://mongodb.github.io/mongo-java-driver/3.12/driver/getting-started/quick-start/)\n\n```\nprivate static final String MONGO_HOST = "xxx.xxx.xxx.xxx";\n\n    private static final Integer MONGO_PORT = 27017;\n\n    private static final String MONGO_DB = "testdb";\n\n    public static void main(String args[]) {\n        try {\n            // 连接到 mongodb 服务\n            MongoClient mongoClient = new MongoClient(MONGO_HOST, MONGO_PORT);\n\n            // 连接到数据库\n            MongoDatabase mongoDatabase = mongoClient.getDatabase(MONGO_DB);\n            System.out.println("Connect to database successfully");\n\n            // 创建Collection\n            mongoDatabase.createCollection("test");\n            System.out.println("create collection");\n\n            // 获取collection\n            MongoCollection<Document> collection = mongoDatabase.getCollection("test");\n\n            // 插入document\n            Document doc = new Document("name", "MongoDB")\n                    .append("type", "database")\n                    .append("count", 1)\n                    .append("info", new Document("x", 203).append("y", 102));\n            collection.insertOne(doc);\n\n            // 统计count\n            System.out.println(collection.countDocuments());\n\n            // query - first\n            Document myDoc = collection.find().first();\n            System.out.println(myDoc.toJson());\n\n            // query - loop all\n            MongoCursor<Document> cursor = collection.find().iterator();\n            try {\n                while (cursor.hasNext()) {\n                    System.out.println(cursor.next().toJson());\n                }\n            } finally {\n                cursor.close();\n            }\n\n        } catch (Exception e) {\n            System.err.println(e.getClass().getName() + ": " + e.getMessage());\n        }\n    }\n```\n\n---\n\n原文链接：https://pdai.tech/md/db/nosql-mongo/mongo-x-usage-4.html','https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=800','NoSQL - MongoDB',NULL,0,NULL,'pdai-db-nosql-mongo-mongo-x-usage-4','Mongo入门 - 基本使用：Java API - 技术博客','例子请参考 mongo-java-driver 例子在新窗口打开http://mongodb.github.io/mongo-java-driver/3.12/driver/getting-started/quick-start/ 原文链接...',0,'PUBLISHED',1202,63,15,7,'2025-07-22 00:00:00','2025-07-22 00:00:00','2026-05-08 23:14:48',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`view_count`=VALUES(`view_count`),`like_count`=VALUES(`like_count`),`favorite_count`=VALUES(`favorite_count`),`comment_count`=VALUES(`comment_count`),`published_at`=VALUES(`published_at`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
