INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES
(300055,2,'Mongo进阶 - WT引擎：数据结构','存储引擎要做的事情无外乎是将磁盘上的数据读到内存并返回给应用，或者将应用修改的数据由内存写到磁盘上。如何设计一种高效的数据结构和算法是所有存储引擎要考虑的根本问题，目前大多数流行的存储引擎是基于B-Tree或LSMLog Structured Merge Tree这两种数据结构来设计的。 像Oracle、SQL Server、DB2、MySQL InnoDB和PostgreSQL这些传统的关系数据库依赖的底层存储引擎是基于B-Tree开发的； 像Cassandra、Elasticsearch L...','# Mongo进阶 - WT引擎：数据结构\n\n> MongoDB的WiredTiger存储引擎背后采用了什么样的数据结构呢？本文将从`常见引擎数据结构`，`典型B-Tree数据结构`，`磁盘数据结构`, `内存数据结构`, `Page数据结构`等方面详解介绍。@pdai\n\n- Mongo进阶 - WT引擎：数据结构存储引擎及常见数据结构典型B-Tree数据结构WiredTiger数据文件在磁盘上的数据结构WiredTiger内存上的基础数据结构page的其它数据结构参考文章\n\n## 存储引擎及常见数据结构\n\n存储引擎要做的事情无外乎是将磁盘上的数据读到内存并返回给应用，或者将应用修改的数据由内存写到磁盘上。如何设计一种高效的数据结构和算法是所有存储引擎要考虑的根本问题，目前大多数流行的存储引擎是基于B-Tree或LSM(Log Structured Merge) Tree这两种数据结构来设计的。\n\n- **B-Tree**\n\n像Oracle、SQL Server、DB2、MySQL (InnoDB)和PostgreSQL这些传统的关系数据库依赖的底层存储引擎是基于B-Tree开发的；\n\n- **LSM Tree**\n\n像Cassandra、Elasticsearch (Lucene)、Google Bigtable、Apache HBase、LevelDB和RocksDB这些当前比较流行的NoSQL数据库存储引擎是基于LSM开发的。\n\n- **插件式兼容上述两种**\n\n当然有些数据库采用了插件式的存储引擎架构，实现了Server层和存储引擎层的解耦，可以支持多种存储引擎，如MySQL既可以支持B-Tree结构的InnoDB存储引擎，还可以支持LSM结构的RocksDB存储引擎。\n\n> 对于MongoDB来说，也采用了插件式存储引擎架构，底层的WiredTiger存储引擎还可以支持B-Tree和LSM两种结构组织数据,但MongoDB在使用WiredTiger作为存储引擎时，目前**默认配置是使用了B-Tree结构**。\n\n因此，本章后面的内容将以B-Tree为核心来分析MongoDB是如何将文档数据在磁盘和内存间进行流传以及WiredTiger存储引擎的其它高级特性。\n\n## 典型B-Tree数据结构\n\n> B-Tree是为磁盘或其它辅助存储设备而设计的一种数据结构，目的是为了在查找数据的过程中减少磁盘I/O的次数。\n\n一个典型的B-Tree结构如下图所示：\n\n![图片](/api/uploads/files/pdai/mongo-y-ds-1-3d95e199da.jpg)\n\n在整个B-Tree中，从上往下依次为Root结点、内部结点和叶子结点，每个结点就是一个Page，数据以Page为单位在内存和磁盘间进行调度，每个Page的大小决定了相应结点的分支数量，每条索引记录会包含一个数据指针，指向一条数据记录所在文件的偏移量。\n\n如上图，假设每个结点100个分支，那么所有叶子结点合起来可以包含100万个键值（等于100*100*100）。通常情况下Root结点和内部结点的Page会驻留在内存中，所以查找一条数据可能只需2次磁盘I/O。但随着数据不断的插入、删除，会涉及到B-Tree结点的分裂、位置提升及合并等操作，因此维护一个B-Tree的平衡也是比较耗时的。\n\n## WiredTiger数据文件在磁盘上的数据结构\n\n对于WiredTiger存储引擎来说，集合所在的数据文件和相应的索引文件都是按B-Tree结构来组织的，**不同之处在于数据文件对应的B-Tree叶子结点上除了存储键名外（keys），还会存储真正的集合数据（values）**，所以数据文件的存储结构也可以认为是一种B+Tree，其整体结构如下图所示：\n\n![图片](/api/uploads/files/pdai/mongo-y-ds-2-e55e69c8cb.jpg)\n\n从上图可以看到，B+ Tree中的leaf page包含一个页头（page header）、块头（block header）和真正的数据（key/value），其中页头定义了页的类型、页中实际载荷数据的大小、页中记录条数等信息；块头定义了此页的checksum、块在磁盘上的寻址位置等信息。\n\nWiredTiger有一个块设备管理的模块，用来为page分配block。如果要定位某一行数据（key/value）的位置，可以先通过block的位置找到此page（相对于文件起始位置的偏移量），再通过page找到行数据的相对位置，最后可以得到行数据相对于文件起始位置的偏移量offsets。由于offsets是一个8字节大小的变量，所以WiredTiger磁盘文件的大小，其最大值可以非常大(264bit)。\n\n## WiredTiger内存上的基础数据结构\n\nWiredTiger会按需将磁盘的数据**以page为单位加载到内存**，同时在内存会构造相应的B-Tree来存储这些数据。**为了高效的支撑CRUD等操作以及将内存里面发生变化的数据持久化到磁盘上**，WiredTiger也会在内存里面维护其它几种数据结构，如下图所示：\n\n![图片](/api/uploads/files/pdai/mongo-y-ds-3-fb329ff91f.jpg)\n\n上图是WiredTiger在内存里面的大概布局图，通过它我们可梳理清楚存储引擎是如何将数据加载到内存，然后如何通过相应数据结构来支持查询、插入、修改操作的。\n\n- 内存里面B-Tree包含三种类型的page，即rootpage、internal page和leaf page，前两者包含指向其子页的page index指针，不包含集合中的真正数据，leaf page包含集合中的真正数据即keys/values和指向父页的home指针；\n- 内存上的leaf page会维护一个`WT_ROW`结构的数组变量，将保存从磁盘leaf page读取的keys/values值，每一条记录还有一个cell_offset变量，表示这条记录在page上的偏移量；\n- 内存上的leaf page会维护一个`WT_UPDATE`结构的数组变量，每条被修改的记录都会有一个数组元素与之对应，如果某条记录被多次修改，则会将所有修改值以链表形式保存。\n- 内存上的leaf page会维护一个`WT_INSERT_HEAD`结构的数组变量，具体插入的data会保存在`WT_INSERT_HEAD`结构中的`WT_UPDATE`属性上，且通过key属性的offset和size可以计算出此条记录待插入的位置；同时，为了提高寻找待插入位置的效率，每个`WT_INSERT_HEAD`变量以**跳转链表**的形式构成。\n\n下图是一个跳转链表的插入示例：\n\n![图片](/api/uploads/files/pdai/mongo-y-ds-4-c5586baca1.jpg)\n\n假如现在插入一个16，最终结果如下：\n\n![图片](/api/uploads/files/pdai/mongo-y-ds-5-63ce17d404.jpg)\n\n如果是一个普通的链表，寻找合适的插入位置时，需要经过：\n\n开始结点->2->5->8->10->20的比较；\n\n对于跳转链表来说只需经过：开始结点->5->10->20的比较，可以看到比在普通链表上寻找插入位置时需要的比较步骤少，所以，**通过跳转链表的数据结构能够提升插入操作的效率**。\n\n## page的其它数据结构\n\n对于一个面向行存储的leaf page来说，包含的数据结构除了上面提到的`WT_ROW`（keys/values）、`WT_UPDATE`（修改数据）、`WT_INSERT_HEAD`（插入数据）外，还有如下几种重要的数据结构：\n\n- **WT_PAGE_MODIFY**：\n\n保存page上事务、脏数据字节大小等与page修改相关的信息；\n\n- **read_gen**：\n\npage的read generation值作为evict page时使用，具体来说对应page在LRU队列中的位置，决定page被evict server选中淘汰出去的先后顺序。\n\n- **WT_PAGE_LOOKASIDE**：\n\npage关联的lookasidetable数据。当对一个page进行reconcile时，如果系统中还有之前的读操作正在访问此page上修改的数据，则会将这些数据保存到lookasidetable；当page再被读时，可以利用lookasidetable中的数据重新构建内存page.\n\n- **WT_ADDR**：\n\npage被成功reconciled后，对应的磁盘上块的地址，将按这个地址将page写到磁盘，块是最小磁盘上文件的最小分配单元，一个page可能有多个块。\n\n- **checksum**：\n\npage的校验和，如果page从磁盘读到内存后没有任何修改，比较checksum可以得到相等结果，那么后续reconcile这个page时，不会将这个page的再重新写入磁盘。\n\n## 参考文章\n\n- [文章来源在新窗口打开](https://mongoing.com/archives/35143)\n- 作者：郭远威\n- MongoDB中文社区委员，长沙分会主席\n- 《大数据存储MongoDB实战指南》作者资深大数据架构师，通信行业业务架构与数据迁移专家\n\n---\n\n原文链接：https://pdai.tech/md/db/nosql-mongo/mongo-y-ds.html','https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=800','NoSQL - MongoDB',NULL,0,NULL,'pdai-db-nosql-mongo-mongo-y-ds','Mongo进阶 - WT引擎：数据结构 - 技术博客','存储引擎要做的事情无外乎是将磁盘上的数据读到内存并返回给应用，或者将应用修改的数据由内存写到磁盘上。如何设计一种高效的数据结构和算法是所有存储引擎要考虑的根本问题，目前大多数流行的存储引擎是基于B-Tree或LSMLog Structure...',0,'PUBLISHED',5173,440,352,7,'2025-09-19 00:00:00','2025-09-19 00:00:00','2026-05-08 23:14:48',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`view_count`=VALUES(`view_count`),`like_count`=VALUES(`like_count`),`favorite_count`=VALUES(`favorite_count`),`comment_count`=VALUES(`comment_count`),`published_at`=VALUES(`published_at`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES
(300056,1,'Mongo进阶 - WT引擎：Page生命周期','通过前文我们了解到数据以page为单位加载到cache、cache里面又会生成各种不同类型的page及为不同类型的page分配不同大小的内存、eviction触发机制和reconcile动作都发生在page上、page大小持续增加时会被分割成多个小page，所有这些操作都是围绕一个page来完成的。 因此，有必要系统的分析一页page的生命周期、状态以及相关参数的配置，这对后续MongoDB的性能调优和故障问题的定位和解决有帮助。 Page的典型生命周期如下图所示： pages的状态是在不断变化...','# Mongo进阶 - WT引擎：Page生命周期\n\n> 通过前文我们了解到数据以page为单位加载到cache; 有必要系统的分析一页page的生命周期、状态以及相关参数的配置，这对后续MongoDB的性能调优和故障问题的定位和解决有帮助。@pdai\n\n- Mongo进阶 - WT引擎：Page生命周期为什么要了解Page生命周期Page的生命周期Page的各种状态Page的大小参数Page无锁及压缩参考文章\n\n## 为什么要了解Page生命周期\n\n通过前文我们了解到数据以page为单位加载到cache、cache里面又会生成各种不同类型的page及为不同类型的page分配不同大小的内存、eviction触发机制和reconcile动作都发生在page上、page大小持续增加时会被分割成多个小page，所有这些操作都是围绕一个page来完成的。\n\n因此，有必要系统的分析一页page的生命周期、状态以及相关参数的配置，这对后续MongoDB的性能调优和故障问题的定位和解决有帮助。\n\n## Page的生命周期\n\nPage的典型生命周期如下图所示：\n\n![图片](/api/uploads/files/pdai/mongo-y-page-1-2d0b6e83b8.png)\n\n- 第一步：pages从磁盘读到内存；\n- 第二步：pages在内存中被修改；\n- 第三步：被修改的脏pages在内存被reconcile，完成后将discard这些pages。\n- 第四步：pages被选中，加入淘汰队列，等待被evict线程淘汰出内存；\n- 第五步：evict线程会将“干净“的pages直接从内存丢弃（因为相对于磁盘page来说没做任何修改），将经过reconcile处理后的磁盘映像写到磁盘再丢弃“脏的”pages。\n\npages的状态是在不断变化的，因此，对于读操作来说，它首先会检查pages的状态是否为`WT_REF_MEM`，然后设置一个hazard指针指向要读的pages，如果刷新后，pages的状态仍为WT_REF_MEM，读操作才能继续处理。\n\n与此同时，evict线程想要淘汰pages时，它会先锁住pages，即将pages的状态设为`WT_REF_LOCKED`，然后检查pages上是否有读操作设置的hazard指针，如有，说明还有线程正在读这个page则停止evict，重新将page的状态设置为`WT_REF_MEM`；如果没有，则pages被淘汰出去。\n\n## Page的各种状态\n\n针对一页page的每一种状态，详细描述如下：\n\n- **WT_REF_DISK**： 初始状态，page在磁盘上的状态，必须被读到内存后才能使用，当page被evict后，状态也会被设置为这个。\n- **WT_REF_DELETED**： page在磁盘上，但是已经从内存B-Tree上删除，当我们不在需要读某个leaf page时，可以将其删除。\n- **WT_REF_LIMBO**： page的映像已经被加载到内存，但page上还有额外的修改数据在lookasidetable上没有被加载到内存。\n- **WT_REF_LOOKASIDE**： page在磁盘上，但是在lookasidetable也有与此page相关的修改内容，在page可读之前，也需要加载这部分内容。\n\n当对一个page进行reconcile时，如果系统中还有之前的读操作正在访问此page上修改的数据，则会将这些数据保存到lookasidetable；当page再被读时，可以利用lookasidetable中的数据重新构建内存page。\n\n- **WT_REF_LOCKED**： 当page被evict时，会将page锁住，其它线程不可访问。\n- **WT_REF_MEM**： page已经从磁盘读到内存，并且能正常访问。\n- **WT_REF_READING**： page正在被某个线程从磁盘读到内存，其它的读线程等待它被读完，不需要重复去读。\n- **WT_REF_SPLIT**： 当page变得过大时，会被split，状态设为WT_REF_SPLIT，原来指向的page不再被使用。\n\n## Page的大小参数\n\n无论将数据从磁盘读到内存，还是从内存写到磁盘，都是以page为单位调度的，但是在磁盘上一个page到底多大？是否是最小分割单元？以及内存里面的各种page的大小对存储引擎的性能是否有影响？本节将围绕这些问题，分析与page大小相关的参数是如何影响存储引擎性能的。 总的来说，涉及到的关键参数和默认值如下表所示：\n\n| 参数名称 | 默认配置值 | 含义 |\n| --- | --- | --- |\n| allocation_size | 4KB | 磁盘上最小分配单元 |\n| memory_page_max | 5MB | 内存中允许的最大page值 |\n| internal_page_max | 4KB | 磁盘上允许的最大internal page值 |\n| leaf_page_max | 32KB | 磁盘上允许的最大leaf page值 |\n| internal_key_max | 1/10*internal_page | internal page上允许的最大key值 |\n| leaf_key_max | 1/10*leaf_page | leaf page上允许的最大key值 |\n| leaf_key_value | 1/2*leaf_page | leaf page上允许的最大value值 |\n| split_pct | 75% | reconciled的page的分割百分比 |\n\n详细说明如下：\n\n- **allocation_size**：\n\nMongoDB磁盘文件的最小分配单元（由WiredTiger自带的块管理模块来分配），一个page的可以由一个或多个这样的单元组成；默认值是4KB，与主机操作系统虚拟内存页的大小相当，大多数场景下不需要修改这个值。\n\n- **memory_page_max**：\n\nWiredTigerCache里面一个内存page随着不断插入修改等操作，允许增长达到的最大值，默认值为5MB。当一个内存page达到这个最大值时，将会被split成较小的内存pages且通过reconcile将这些pages写到磁盘pages，一旦完成写到磁盘，这些内存pages将从内存移除。\n\n需要注意的是：split和reconcile这两个动作都需要获得page的排它锁，导致应用程序在此page上的其它写操作会等待，因此设置一个合理的最大值，对系统的性能也很关键。\n\n如果值太大，虽然spilt和reconcile发生的机率减少，但一旦发生这样的动作，持有排它锁的时间会较长，导致应用程序的插入或修改操作延迟增大；\n\n如果值太小，虽然单次持有排它锁的时间会较短，但是会导致spilt和reconcile发生的机率增加。\n\n- **internal_page_max**：\n\n磁盘上internalpage的最大值，默认为4KB。随着reconcile进行，internalpage超过这个值时，会被split成多个pages。\n\n这个值的大小会影响磁盘上B-Tree的深度和internalpage上key的数量，如果太大，则internalpage上的key的数量会很多，通过遍历定位到正确leaf page的时间会增加；如果太小，则B-Tree的深度会增加，也会影响定位到正确leaf page的时间。\n\n- **leaf_page_max**：\n\n磁盘上leaf page的最大值，默认为32KB。随着reconcile进行，leaf page超过这个值时，会被split成多个pages。\n\n这个值的大小会影响磁盘的I/O性能，因为我们在从磁盘读取数据时，总是期望一次I/O能多读取一点数据，所以希望把这个参数调大；但是太大，又会造成读写放大，因为读出来的很多数据可能后续都用不上。\n\n- **internal_key_max**：\n\ninternalpage上允许的最大key值，默认大小为internalpage初始值的1/10，如果超过这个值，将会额外存储。导致读取key时需要额外的磁盘I/O。\n\n- **leaf_key_max**：\n\nleaf page上允许的最大key值，默认大小为leaf page初始值的1/10，如果超过这个值，将会额外存储。导致读取key时需要额外的磁盘I/O。\n\n- **leaf_value_max**：\n\nleaf page上允许的最大value值（保存真正的集合数据），默认大小为leaf page初始值的1/2，如果超过这个值，将会额外存储。导致读取value时需要额外的磁盘I/O。\n\n- **split_pct**：\n\n内存里面将要被reconciled的 page大小与internal_page_max或leaf_page_max值的百分比，默认值为75%，如果内存里面被reconciled的page能够装进一个单独的磁盘page上，则不会发生spilt，否则按照该百分比值*最大允许的page值分割新page的大小。\n\n## Page无锁及压缩\n\nhttps://blog.csdn.net/weixin_45583158/article/details/100143033\n\n## 参考文章\n\n- [文章来源在新窗口打开](https://mongoing.com/archives/57177)\n- 作者：郭远威\n- MongoDB中文社区委员，长沙分会主席;《大数据存储MongoDB实战指南》作者资深大数据架构师，通信行业业务架构与数据迁移专家\n- [文章来源在新窗口打开](https://blog.csdn.net/weixin_45583158/article/details/100143033)\n- 袁荣喜，学霸君工程师，2015年加入学霸君，负责学霸君的网络实时传输和分布式系统的架构设计和实现，专注于基础技术领域，在网络传输、数据库内核、分布式系统和并发编程方面有一定了解\n\n---\n\n原文链接：https://pdai.tech/md/db/nosql-mongo/mongo-y-page.html','https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=800','NoSQL - MongoDB',NULL,0,NULL,'pdai-db-nosql-mongo-mongo-y-page','Mongo进阶 - WT引擎：Page生命周期 - 技术博客','通过前文我们了解到数据以page为单位加载到cache、cache里面又会生成各种不同类型的page及为不同类型的page分配不同大小的内存、eviction触发机制和reconcile动作都发生在page上、page大小持续增加时会被分割...',0,'PUBLISHED',3487,316,99,20,'2025-07-27 00:00:00','2025-07-27 00:00:00','2026-05-08 23:14:48',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`view_count`=VALUES(`view_count`),`like_count`=VALUES(`like_count`),`favorite_count`=VALUES(`favorite_count`),`comment_count`=VALUES(`comment_count`),`published_at`=VALUES(`published_at`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
