(300090,1,'ElasticSearch - WrapperQuery','https://www.elastic.co/guide/en/elasticsearch/reference/6.4/query-dsl-wrapper-query.html https://blog.csdn.net/qq41370896/article/details/83658948 https://blog.csdn.net/tcyzhyx/article/details/84566734 https://www.jianshu.com/p/216ca70d9e62','# ElasticSearch - WrapperQuery\n\n> 在工作中遇到ElasticSearch版本升级时出现Java High Level接口变更导致的兼容性问题: 之前使用的是2.4.x，考虑性能和功能的增强，需要更换为6.4.x; 2.4.x中我们使用DSL语句直接查询(数据的不确定性和方便动态建立查询规则等因素)，而新的ES Java 高阶API中去掉了相关接口的支持。 此文主要记录通过 ES Wrapper Query实现对6.x版本中 Java high-level transport client对json DSL查询对支持。 @pdai\n\n## 实现方式理论基础\n\n- Wrapper Query 官网说明\n\nhttps://www.elastic.co/guide/en/elasticsearch/reference/6.4/query-dsl-wrapper-query.html\n\n> This query is more useful in the context of the Java high-level REST client or transport client to also accept queries as json formatted string. In these cases queries can be specified as a json or yaml formatted string or as a query builder (which is a available in the Java high-level REST client).\n\n```\nGET /_search\n{\n    "query" : {\n        "wrapper": {\n            "query" : "eyJ0ZXJtIiA6IHsgInVzZXIiIDogIktpbWNoeSIgfX0=" // Base64 encoded string: {"term" : { "user" : "Kimchy" }}\n        }\n    }\n}\n```\n\n- 将DSL JSON语句 转成 map\n\nhttps://blog.csdn.net/qq_41370896/article/details/83658948\n\n```\nString dsl = "";\nMap maps = (Map)JSON.parse(dsl);  \nmaps.get("query");// dsl query string\n```\n\n- Java 代码\n\nhttps://blog.csdn.net/tcyzhyx/article/details/84566734\n\nhttps://www.jianshu.com/p/216ca70d9e62\n\n```\nStringBuffer dsl = new StringBuffer();\ndsl.append("{\\"bool\\": {");\ndsl.append("      \\"must\\": [");\ndsl.append("        {");\ndsl.append("          \\"term\\": {");\ndsl.append("            \\"mdid.keyword\\": {");\ndsl.append("              \\"value\\": \\"2fa9d41e1af460e0d47ce36ca8a98737\\"");\ndsl.append("            }");\ndsl.append("          }");\ndsl.append("        }");\ndsl.append("      ]");\ndsl.append("    }");\ndsl.append("}");\nWrapperQueryBuilder wqb = QueryBuilders.wrapperQuery(dsl.toString());\nSearchResponse searchResponse = client.prepareSearch(basicsysCodeManager.getYjzxYjxxIndex())\n.setTypes(basicsysCodeManager.getYjzxYjxxType()).setQuery(wqb).setSize(10).get();\nSearchHit[] hits = searchResponse.getHits().getHits();\nfor(SearchHit hit : hits){\n\tString content = hit.getSourceAsString();\n\tSystem.out.println(content);\n}\n```\n\n- query + agg 应该怎么写\n\nhttp://www.itkeyword.com/doc/1009692843717298639/wrapperquerybuilder-aggs-query-throwing-query-malformed-exception\n\n```\n"{\\"query\\":{\\"match_all\\": {}},\\"aggs\\":{\\"avg1\\":{\\"avg\\":{\\"field\\":\\"age\\"}}}}"\n```\n\n```\nSearchSourceBuilder ssb = new SearchSourceBuilder();\n\n// add the query part\nString query ="{\\"match_all\\": {}}";\nWrapperQueryBuilder wrapQB = new WrapperQueryBuilder(query);\nssb.query(wrapQB);\n\n// add the aggregation part\nAvgBuilder avgAgg = AggregationBuilders.avg("avg1").field("age");\nssb.aggregation(avgAgg);\n```\n\n## 实现示例\n\n略\n\n---\n\n原文链接：https://pdai.tech/md/db/nosql-es/elasticsearch-wrapper-query.html','https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=800','NoSQL - ElasticSearch',NULL,0,NULL,'pdai-db-nosql-es-elasticsearch-wrapper-query','ElasticSearch - WrapperQuery - 技术博客','https://www.elastic.co/guide/en/elasticsearch/reference/6.4/query-dsl-wrapper-query.html https://blog.csdn.net/qq4137089...',0,'PUBLISHED',7990,1141,337,68,'2025-08-30 00:00:00','2025-08-30 00:00:00','2026-05-08 23:14:48',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`view_count`=VALUES(`view_count`),`like_count`=VALUES(`like_count`),`favorite_count`=VALUES(`favorite_count`),`comment_count`=VALUES(`comment_count`),`published_at`=VALUES(`published_at`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES
(300091,2,'ElasticSearch - 备份和迁移','注册前要注意配置文件加上: elasticsearch.yml 原文链接：https://pdai.tech/md/db/nosql-es/elasticsearch-backup.html','# ElasticSearch - 备份和迁移\n\n- ElasticSearch - 备份和迁移方案离线方案增量备份方案使用快照进行备份配置信息创建仓库创建快照恢复数据方案使用场景迁移考虑的问题\n\n## 方案\n\n### 离线方案\n\n- Snapshot\n- Reindex\n- Logstash\n- ElasticSearch-dump\n- ElasticSearch-Exporter\n\n### 增量备份方案\n\n- logstash\n\n## 使用快照进行备份\n\n### 配置信息\n\n注册前要注意配置文件加上: elasticsearch.yml\n\n```\npath.repo: ["/opt/elasticsearch/backup"]\n```\n\n### 创建仓库\n\n> 注册一个仓库，存放快照，记住，这里不是生成快照，只是注册一个仓库\n\n```\ncurl -XPUT \'http://10.11.60.5:9200/_snapshot/repo_backup_1\' -H \'Content-Type: application/json\' -d \'{\n\t"type": "fs",\n\t"settings": {\n\t\t"location": "/opt/elasticsearch/backup",\n\t\t"max_snapshot_bytes_per_sec": "20mb",\n\t\t"max_restore_bytes_per_sec": "20mb",\n\t\t"compress": true\n\t}\n}\'\n```\n\n查看仓库信息:\n\n```\ncurl -XGET \'http://10.11.60.5:9200/_snapshot/repo_backup_1?pretty\'\n```\n\n返回内容\n\n```\n[root@STOR-ES elasticsearch]# curl -XGET \'http://10.11.60.5:9200/_snapshot/repo_backup_1?pretty\'\n{\n  "repo_backup_1" : {\n    "type" : "fs",\n    "settings" : {\n      "location" : "/opt/elasticsearch/backup",\n      "max_restore_bytes_per_sec" : "20mb",\n      "compress" : "true",\n      "max_snapshot_bytes_per_sec" : "20mb"\n    }\n  }\n}\n```\n\n### 创建快照\n\n```\ncurl -XPUT \'http://10.11.60.5:9200/_snapshot/repo_backup_1/snapshot_1?wait_for_completion=true&pretty\' -H \'Content-Type: application/json\' -d \'{\n\t"indices": "bro-2019-09-14,bro-2019-09-15,wmi-2019-09-14,wmi-2019-09-15,syslog-2019-09-14,sylog-2019-09-15",\n\t"rename_pattern": "bro_(.+)",\n\t"rename_replacement": "dev_bro_$1",\n\t"ignore_unavailable": true,\n\t"include_global_state": true\n}\'\n```\n\n执行\n\n```\n{\n  "snapshot" : {\n    "snapshot" : "snapshot_1",\n    "version_id" : 2040399,\n    "version" : "2.4.3",\n    "indices" : [ "bro-2019-09-14", "bro-2019-09-15", "wmi-2019-09-15", "syslog-2019-09-14", "wmi-2019-09-14" ],\n    "state" : "SUCCESS",\n    "start_time" : "2019-09-18T05:58:08.860Z",\n    "start_time_in_millis" : 1568786288860,\n    "end_time" : "2019-09-18T06:02:18.037Z",\n    "end_time_in_millis" : 1568786538037,\n    "duration_in_millis" : 249177,\n    "failures" : [ ],\n    "shards" : {\n      "total" : 25,\n      "failed" : 0,\n      "successful" : 25\n    }\n  }\n}\n```\n\n### 恢复数据\n\n## 方案使用场景\n\n## 迁移考虑的问题\n\n- 版本问题，从低版本到高版本数据的迁移\n- 多租户的适配问题\n\n> 多个工厂的数据进入不同index, 原有的数据bro-2019-09-15的数据需要进入factorycode-bro-2019-09-15\n\n- 多次或者分批迁移数据\n- 数据在迁移时候富化\n- FieldMapping 和 数据信息 分离?\n\n---\n\n原文链接：https://pdai.tech/md/db/nosql-es/elasticsearch-backup.html','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','NoSQL - ElasticSearch',NULL,0,NULL,'pdai-db-nosql-es-elasticsearch-backup','ElasticSearch - 备份和迁移 - 技术博客','注册前要注意配置文件加上: elasticsearch.yml 原文链接：https://pdai.tech/md/db/nosql-es/elasticsearch-backup.html',0,'PUBLISHED',3070,80,167,8,'2025-08-31 00:00:00','2025-08-31 00:00:00','2026-05-08 23:14:48',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`view_count`=VALUES(`view_count`),`like_count`=VALUES(`like_count`),`favorite_count`=VALUES(`favorite_count`),`comment_count`=VALUES(`comment_count`),`published_at`=VALUES(`published_at`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
